<script>
  import { onMount, onDestroy } from 'svelte';

  /** Show caption bubbles during the tour */
  export let showCaptions = true;
  /** Start the tour automatically when mounted */
  export let autoplay = true;
  /** Loop the tour when it finishes */
  export let loop = true;
  /** Show the replay button */
  export let showReplayButton = false;
  /** Show the bottom progress bar */
  export let showProgress = true;

  const IMAGES = {
  configs: 'data:image/webp;base64,',
  schema: 'data:image/webp;base64,',
  s31: 'data:image/webp;base64,',
  s32: 'data:image/webp;base64,',
  s33: 'data:image/webp;base64,',
  s34: 'data:image/webp;base64,',
  s35: 'data:image/webp;base64,',
  s36: 'data:image/webp;base64,',
  s37: 'data:image/webp;base64,',
  s38: 'data:image/webp;base64,',
  orders: 'data:image/webp;base64,',
  orderid: 'data:image/webp;base64,',
  orderdate: 'data:image/webp;base64,',
  tax: 'data:image/webp;base64,',
  tax_hover: 'data:image/webp;base64,',
  semantics: 'data:image/webp;base64,',
  order_open: 'data:image/webp;base64,',
  glossary: 'data:image/webp;base64,',
  };

  // ----- Reactive state -----
  let currentScreen = 'configs';
  let screenFast = false;
  let cursorX = 50;
  let cursorY = 50;
  let cursorType = 'arrow';
  let cursorPressed = false;
  let cursorFast = false;
  let zoomCx = 0, zoomCy = 0, zoomS = 1;
  let captionText = '';
  let captionVisible = false;
  let progress = 0;
  let playing = false;

  $: cursorVisualX = cursorX * zoomS + zoomCx * (1 - zoomS);
  $: cursorVisualY = cursorY * zoomS + zoomCy * (1 - zoomS);
  $: stageTransform = `translate(${zoomCx * (1 - zoomS)}%, ${zoomCy * (1 - zoomS)}%) scale(${zoomS})`;

  const TOTAL_MS = 58000;
  let startedAt = 0;
  let progressTimer = null;
  let cancelToken = 0;

  const wait = (ms) => new Promise((r) => setTimeout(r, ms));

  function moveCursor(x, y) { cursorX = x; cursorY = y; }
  function setCursor(t) { cursorType = t; }
  function setCursorSpeed(fast) { cursorFast = fast; }
  function showScreen(id, fast = false) { screenFast = fast; currentScreen = id; }
  function zoomTo(x, y, s) { zoomCx = x; zoomCy = y; zoomS = s; }
  function resetZoom() { zoomTo(0, 0, 1); }
  function showCaption(text) { captionText = text; captionVisible = true; }
  function hideCaption() { captionVisible = false; }

  async function pointerClick() {
    setCursor('pointer');
    await wait(220);
    cursorPressed = true;
    await wait(130);
    cursorPressed = false;
    await wait(140);
  }

  // Cancellable wait — bails early if a new play() starts
  async function w(ms, token) {
    await wait(ms);
    if (token !== cancelToken) throw new Error('cancelled');
  }

  export async function play() {
    cancelToken += 1;
    const token = cancelToken;
    playing = true;

    if (progressTimer) { clearInterval(progressTimer); progressTimer = null; }

    try {
      // reset
      resetZoom();
      showScreen('configs');
      setCursor('arrow');
      moveCursor(50, 60);
      hideCaption();
      progress = 0;
      await w(500, token);

      startedAt = Date.now();
      progressTimer = setInterval(() => {
        const p = Math.min(100, ((Date.now() - startedAt) / TOTAL_MS) * 100);
        progress = p;
        if (p >= 100 && progressTimer) { clearInterval(progressTimer); progressTimer = null; }
      }, 80);

      // 1. CONFIGS / SOURCES
      showCaption('Welcome to nomox - your data, instantly understood');
      await w(2300, token);
      hideCaption();
      await w(250, token);

      showCaption('Connect any database - Postgres, Mongo, and more');
      moveCursor(27, 22.6);
      await w(1100, token);
      moveCursor(26, 29.6);
      await w(900, token);
      moveCursor(26, 36.5);
      await w(1100, token);
      hideCaption();
      await w(200, token);

      // 2. NAVIGATE TO CATALOG / SCHEMA
      moveCursor(4.4, 24.7);
      await w(700, token);
      await pointerClick();
      showScreen('schema');
      await w(250, token);
      setCursor('arrow');
      await w(550, token);

      showCaption('Auto-generated catalog with business semantics');
      await w(2200, token);
      hideCaption();
      await w(200, token);

      zoomTo(62, 32, 1.35);
      await w(2500, token);
      showCaption('AI-inferred domain, description, and table structure');
      await w(2400, token);
      hideCaption();
      resetZoom();
      await w(700, token);

      // 3. SCAN THE TREE
      setCursorSpeed(true);
      const treeItems = [
        ['s31', 33.2], ['s32', 36.4], ['s33', 39.5], ['s34', 42.7],
        ['s35', 45.8], ['s36', 49.0], ['s37', 52.1], ['s38', 55.3],
      ];
      for (const [scr, y] of treeItems) {
        showScreen(scr, true);
        moveCursor(29.1, y);
        await w(420, token);
      }
      await w(300, token);
      setCursorSpeed(false);

      showScreen('s31', true);
      moveCursor(29.1, 33.2);
      await w(700, token);

      // 4. CLICK ORDERS
      await pointerClick();
      showScreen('orders');
      await w(300, token);
      setCursor('arrow');
      moveCursor(48, 30);
      await w(700, token);

      showCaption('12,000 rows of orders - every column documented');
      await w(2400, token);
      hideCaption();
      await w(200, token);

      // 5. ORDERID
      moveCursor(26.9, 54.3);
      await w(700, token);
      await pointerClick();
      showScreen('orderid');
      await w(300, token);
      setCursor('arrow');
      moveCursor(48, 70);
      await w(500, token);

      showCaption('Business meaning + data profiling, AI-inferred');
      await w(2600, token);
      hideCaption();
      await w(200, token);

      // 6. ORDERDATE
      moveCursor(26.9, 59.8);
      await w(700, token);
      await pointerClick();
      showScreen('orderdate');
      await w(300, token);
      setCursor('arrow');
      moveCursor(48, 73);
      await w(1700, token);

      // 7. TAX
      moveCursor(26.9, 75.8);
      await w(800, token);
      await pointerClick();
      showScreen('tax');
      await w(300, token);
      setCursor('arrow');
      moveCursor(75, 87);
      await w(500, token);

      showCaption('Distinct values, ranges, nulls - fully profiled');
      await w(2800, token);
      hideCaption();
      await w(200, token);

      // 8. CLICK SEMANTICS
      moveCursor(8.8, 24.7);
      await w(700, token);
      setCursor('pointer');
      showScreen('tax_hover');
      await w(800, token);
      cursorPressed = true;
      await w(130, token);
      cursorPressed = false;
      showScreen('semantics');
      await w(350, token);
      setCursor('arrow');
      moveCursor(50, 40);
      await w(600, token);

      showCaption('Inferred entities - your business model, auto-discovered');
      await w(2400, token);
      hideCaption();
      await w(200, token);

      // 9. EXPAND ORDER
      moveCursor(70, 28);
      await w(900, token);
      moveCursor(95.4, 26.5);
      await w(500, token);
      await pointerClick();
      showScreen('order_open');
      await w(350, token);
      setCursor('arrow');
      moveCursor(50, 50);
      await w(600, token);

      showCaption('"Order" lives in 3 tables - unified into one entity');
      await w(2800, token);
      hideCaption();
      await w(200, token);

      // 10. GLOSSARY
      moveCursor(30.9, 16.5);
      await w(700, token);
      await pointerClick();
      showScreen('glossary');
      await w(350, token);
      setCursor('arrow');
      moveCursor(60, 45);
      await w(700, token);

      showCaption('Glossary - every business term, defined and linked');
      await w(3000, token);
      hideCaption();
      await w(400, token);

      setCursor('arrow');
      playing = false;

      if (loop) play();
    } catch (e) {
      // cancelled — silent
    }
  }

  function restart() { play(); }

  onMount(() => { if (autoplay) play(); });
  onDestroy(() => {
    cancelToken += 1;
    if (progressTimer) clearInterval(progressTimer);
  });
</script>

<div class="nomox-demo">
  <div class="stage-wrap">
    <div class="stage" style="transform: {stageTransform}">
      {#each Object.entries(IMAGES) as [id, src] (id)}
        <img
          class="screen"
          class:active={currentScreen === id}
          class:fast={screenFast}
          {src}
          alt=""
          draggable="false"
        />
      {/each}
    </div>

    <div
      class="cursor"
      class:pointer={cursorType === 'pointer'}
      class:pressed={cursorPressed}
      class:fast={cursorFast}
      style="left: {cursorVisualX}%; top: {cursorVisualY}%"
    >
      {#if cursorType === 'arrow'}
        <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
          <path
            d="M3 2 L3 19 L7.8 14.4 L11.2 22 L14 20.9 L10.6 13.4 L17 13.4 Z"
            fill="white"
            stroke="#111"
            stroke-width="1.3"
            stroke-linejoin="round"
          />
        </svg>
      {:else}
        <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
          <path
            d="M8 11 L8 4.5 C8 3.7 8.7 3 9.5 3 C10.3 3 11 3.7 11 4.5 L11 10
               L11 8 C11 7.2 11.7 6.5 12.5 6.5 C13.3 6.5 14 7.2 14 8 L14 10.5
               L14 9 C14 8.2 14.7 7.5 15.5 7.5 C16.3 7.5 17 8.2 17 9 L17 11
               L17 10 C17 9.2 17.7 8.5 18.5 8.5 C19.3 8.5 20 9.2 20 10 L20 16
               C20 19.3 17.3 22 14 22 L12 22 C9.5 22 7.5 20.5 6.5 18.5
               L4 13.5 C3.6 12.7 4 11.7 4.8 11.4 C5.6 11.1 6.5 11.4 7 12.1 L8 13.5 Z"
            fill="white"
            stroke="#111"
            stroke-width="1.3"
            stroke-linejoin="round"
          />
        </svg>
      {/if}
    </div>

    {#if showCaptions}
      <div class="caption" class:show={captionVisible}>{captionText}</div>
    {/if}

    {#if showProgress}
      <div class="progress" style="width: {progress}%"></div>
    {/if}

    {#if showReplayButton && !playing}
      <button class="replay-btn" on:click={restart} aria-label="Replay">
        &#x21bb; Replay
      </button>
    {/if}
  </div>
</div>

<style>
  .nomox-demo {
    width: 100%;
    display: flex;
    justify-content: center;
  }
  .stage-wrap {
    position: relative;
    width: 100%;
    max-width: 1700px;
    aspect-ratio: 2854 / 1530;
    overflow: hidden;
    background: #fff;
  }
  .stage {
    position: absolute;
    inset: 0;
    transform-origin: 0 0;
    transition: transform 1.2s cubic-bezier(0.65, 0, 0.35, 1);
    will-change: transform;
  }
  .screen {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    transform: scale(1.017);
    transform-origin: center;
    opacity: 0;
    transition: opacity 0.45s ease;
    pointer-events: none;
    user-select: none;
  }
  .screen.active { opacity: 1; }
  .screen.fast { transition: opacity 0.18s ease; }

  .cursor {
    position: absolute;
    width: 20px;
    height: 20px;
    pointer-events: none;
    z-index: 3;
    transition:
      left 0.85s cubic-bezier(0.5, 0, 0.2, 1),
      top 0.85s cubic-bezier(0.5, 0, 0.2, 1),
      transform 0.12s ease;
    filter: drop-shadow(0 3px 6px rgba(0, 0, 0, 0.3));
    transform: translate(-2px, -2px);
  }
  .cursor.fast {
    transition:
      left 0.5s cubic-bezier(0.5, 0, 0.2, 1),
      top 0.5s cubic-bezier(0.5, 0, 0.2, 1),
      transform 0.12s ease;
  }
  .cursor :global(svg) { width: 100%; height: 100%; display: block; }
  .cursor.pointer { transform: translate(-9px, -3px); }
  .cursor.pressed { transform: translate(-9px, -3px) scale(0.85); }

  .caption {
    position: absolute;
    bottom: 20px;
    left: 50%;
    transform: translateX(-50%) translateY(14px);
    background: rgba(255, 255, 255, 0.7);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    color: oklch(0.141 0.005 285.823);
    padding: 7px 18px;
    border-radius: 999px;
    font-size: 12px;
    font-weight: 500;
    font-family: Inter, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    letter-spacing: 0.01em;
    opacity: 0;
    transition:
      opacity 0.5s ease,
      transform 0.5s cubic-bezier(0.2, 0.8, 0.3, 1);
    border: 1px solid rgba(0, 0, 0, 0.08);
    white-space: nowrap;
    z-index: 4;
    max-width: 90%;
    pointer-events: none;
  }
  .caption.show {
    opacity: 1;
    transform: translateX(-50%) translateY(0);
  }

  .progress {
    position: absolute;
    bottom: 0;
    left: 0;
    height: 3px;
    background: #4f8cff;
    width: 0%;
    transition: width 0.15s linear;
    box-shadow: none;
    z-index: 5;
  }

  .replay-btn {
    position: absolute;
    top: 16px;
    right: 16px;
    background: rgba(12, 12, 20, 0.85);
    color: #fff;
    border: 1px solid rgba(255, 255, 255, 0.18);
    padding: 8px 16px;
    border-radius: 10px;
    font-size: 13px;
    font-weight: 500;
    cursor: pointer;
    font-family: inherit;
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    transition: all 0.2s;
    z-index: 6;
  }
  .replay-btn:hover {
    background: rgba(20, 20, 30, 0.95);
    border-color: rgba(255, 255, 255, 0.3);
  }
</style>